// 1. 定义 API 格式模板 (Prompt JSON)
const bgWorkflowRaw = {
  "1": { "inputs": { "unet_name": "z_image_turbo_bf16.safetensors", "weight_dtype": "default" }, "class_type": "UNETLoader" },
  "2": { "inputs": { "vae_name": "ae.safetensors" }, "class_type": "VAELoader" },
  "3": { "inputs": { "clip_name": "qwen_3_4b.safetensors", "type": "lumina2", "device": "default" }, "class_type": "CLIPLoader" },
  "4": { "inputs": { "shift": 3, "model": ["1", 0] }, "class_type": "ModelSamplingAuraFlow" },
  "5": { "inputs": { "width": 2048, "height": 1152, "batch_size": 1 }, "class_type": "EmptySD3LatentImage" },
  "6": { "inputs": { "text": "", "clip": ["3", 0] }, "class_type": "CLIPTextEncode" },
  "7": { "inputs": { "text": "", "clip": ["3", 0] }, "class_type": "CLIPTextEncode" },
  "8": { "inputs": { "seed": 0, "steps": 15, "cfg": 1.5, "sampler_name": "euler", "scheduler": "simple", "denoise": 1, "model": ["4", 0], "positive": ["6", 0], "negative": ["7", 0], "latent_image": ["5", 0] }, "class_type": "KSampler" },
  "9": { "inputs": { "samples": ["8", 0], "vae": ["2", 0] }, "class_type": "VAEDecode" },
  "10": { "inputs": { "filename_prefix": "Universal_Scene", "images": ["9", 0] }, "class_type": "SaveImage" }
};

const charWorkflowRaw = {
  "1": { "inputs": { "unet_name": "z_image_turbo_bf16.safetensors", "weight_dtype": "default" }, "class_type": "UNETLoader" },
  "2": { "inputs": { "vae_name": "ae.safetensors" }, "class_type": "VAELoader" },
  "3": { "inputs": { "clip_name": "qwen_3_4b.safetensors", "type": "lumina2", "device": "default" }, "class_type": "CLIPLoader" },
  "4": { "inputs": { "shift": 3, "model": ["1", 0] }, "class_type": "ModelSamplingAuraFlow" },
  "5": { "inputs": { "width": 1024, "height": 1024, "batch_size": 1 }, "class_type": "EmptySD3LatentImage" },
  "7": { "inputs": { "text": "", "clip": ["3", 0] }, "class_type": "CLIPTextEncode" },
  "101": { "inputs": { "lora_name": "poppy.safetensors", "strength_model": 0.8, "strength_clip": 1, "model": ["4", 0], "clip": ["3", 0] }, "class_type": "LoraLoader" },
  "102": { "inputs": { "text": "", "clip": ["101", 1] }, "class_type": "CLIPTextEncode" },
  "103": { "inputs": { "seed": 0, "steps": 20, "cfg": 1.5, "sampler_name": "euler", "scheduler": "simple", "denoise": 1, "model": ["101", 0], "positive": ["102", 0], "negative": ["7", 0], "latent_image": ["5", 0] }, "class_type": "KSampler" },
  "104": { "inputs": { "samples": ["103", 0], "vae": ["2", 0] }, "class_type": "VAEDecode" },
  "105": { "inputs": { "filename_prefix": "Asset_Poppy", "images": ["104", 0] }, "class_type": "SaveImage" }
};

// --- 核心逻辑开始 ---

// 2. 解析 Webhook body
const inputData = $input.first()?.json || {};
const body = inputData.body || {};

// 判断角色：如果有 name 字段就用 name，否则默认为 bg
const role = (body.name || 'bg').toLowerCase();
// 提取提示词：直接取 body.prompt
const userPrompt = body.prompt || "";
const userNegative = body.negative_prompt || "blurry, low quality, 3d, realistic";

// 机器 URL 映射
const comfyuiUrls = {
  'poppy': 'https://vcbj5meqyp1y7ifw-8188.container.x-gpu.com',
  'edi': 'https://vcbj5meqyp1y7ifw-8188.container.x-gpu.com',
  'rolly': 'https://vcbj5meqyp1y7ifw-8188.container.x-gpu.com',
  'milo': 'https://vcbj5meqyp1y7ifw-8188.container.x-gpu.com',
  'ace': 'https://vcbj5meqyp1y7ifw-8188.container.x-gpu.com',
  'bg': 'https://vcbj5meqyp1y7ifw-8188.container.x-gpu.com'
};

// 3. 参数注入
let finalPrompt = JSON.parse(JSON.stringify(role === 'bg' ? bgWorkflowRaw : charWorkflowRaw));

if (role === 'bg') {
  // 背景逻辑：注入到 6 号和 7 号节点
  finalPrompt["6"].inputs.text = userPrompt;
  finalPrompt["7"].inputs.text = userNegative;
  finalPrompt["8"].inputs.seed = Math.floor(Math.random() * 100000000000000);
} else {
  // 角色逻辑：注入到 102 号和 7 号节点
  finalPrompt["102"].inputs.text = userPrompt;
  finalPrompt["7"].inputs.text = userNegative;
  finalPrompt["103"].inputs.seed = Math.floor(Math.random() * 100000000000000);

  // 动态修改 LoRA 名称和尺寸
  if (finalPrompt["101"]) {
    finalPrompt["101"].inputs.lora_name = `${role}.safetensors`;
    finalPrompt["105"].inputs.filename_prefix = `Asset_${role}`;
  }
  // 如果 body 传了宽高，覆盖默认值
  if (body.width) finalPrompt["5"].inputs.width = body.width;
  if (body.height) finalPrompt["5"].inputs.height = body.height;
}

// 4. 返回结果
return [{
  json: {
    comfyui_url: comfyuiUrls[role] || comfyuiUrls.bg,
    comfyui_payload: { prompt: finalPrompt },
    meta: { 
      target_role: role, 
      applied_prompt: userPrompt // 确认这里不是空的
    }
  }
}];

// 提取 prompt_id 和 comfyui_url
const response = $input.first()?.json || {};
const promptId = response?.prompt_id || response?.id;
const comfyuiUrl = response?.comfyui_url || '';

return [{
  json: {
    executionId: promptId,
    comfyuiUrl: comfyuiUrl,
    workflowType: 'image',
    status: 'submitted'
  }
}];
